def fib_top_down(n):
    memo = {} #以dictionary記錄每一層費式數列的數值避免重複計算
    def fib(m):
        if m in memo:
            return memo[m] #如果有算過就直接從memo中拿
        if m <= 1:
            return m
        memo[m] = fib(m-1) + fib(m-2)
        return memo[m]
    return fib(n)

def fib_bottom_up(n):
    if n<=1:
        return n
    dp = [0]*(n+1) #實際上為優化空間不需要(這邊是為了演示dp做法)
    dp[1] = 1
    for i in range(2,n+1):
        dp[i] = dp[i-1] + dp[i-2]

    return dp[n]
